using System;
using System.IO;
using System.Text;

class Program
{
    static void Main(string[] args)
    {
        string filePath = @"C:\Users\Administrator\Desktop\1cellAssembleMachine\I_O 파라미터.iop";
        string outPath = @"C:\Users\Administrator\Desktop\iop_result.txt";

        byte[] bytes = File.ReadAllBytes(filePath);

        using var sw = new StreamWriter(outPath, false, Encoding.UTF8);

        sw.WriteLine($"File: {filePath}");
        sw.WriteLine($"Size: {bytes.Length} bytes");
        sw.WriteLine();

        // Hex dump first 600 bytes
        sw.WriteLine("=== HEX DUMP (first 600 bytes) ===");
        int limit = Math.Min(600, bytes.Length);
        for (int i = 0; i < limit; i += 16)
        {
            int end = Math.Min(i + 15, limit - 1);
            var hexParts = new System.Collections.Generic.List<string>();
            var ascParts = new System.Collections.Generic.List<char>();
            for (int j = i; j <= end; j++)
            {
                hexParts.Add(bytes[j].ToString("X2"));
                ascParts.Add(bytes[j] >= 32 && bytes[j] <= 126 ? (char)bytes[j] : '.');
            }
            sw.WriteLine($"{i:X4}  {string.Join(" ", hexParts),-48}  {new string(ascParts.ToArray())}");
        }

        sw.WriteLine();
        sw.WriteLine("=== FULL TEXT (CP949) ===");
        var enc = Encoding.GetEncoding(949);
        string text = enc.GetString(bytes);
        sw.WriteLine(text);

        sw.WriteLine();
        sw.WriteLine("=== FULL TEXT (UTF-16 LE) ===");
        string textU16 = Encoding.Unicode.GetString(bytes);
        sw.WriteLine(textU16);
    }
}

